+                dml,
+                Statement::Insert(_) | Statement::Update(_) | Statement::Delete(_)
+            );
+            Ok(if is_dml {
+                *self.last_changes.borrow()
+            } else {
+                rows.len()
+            })
+        } else {
+            // SELECT prepared statement — delegate to query path.
+            Ok(if params.is_empty() {
+                stmt.query()?.len()
+            } else {
+                stmt.query_with_params(params)?.len()
+            })
+        }
